import React, { useState, useRef, useCallback, memo } from "react";
import { procesarConsulta, EJEMPLOS_CONSULTA } from "../utils/orchestrator";
import { useObras } from "../context/ObraContext";

function OrchestradorPanel() {
  const { obras }              = useObras();
  const [pregunta, setPregunta] = useState("");
  const [historial, setHistorial] = useState([]); // [{ pregunta, respuesta, confianza, sql, sugerencias }]
  const [loading,  setLoading]  = useState(false);
  const inputRef = useRef(null);

  const handleConsultar = useCallback(() => {
    if (!pregunta.trim()) return;
    setLoading(true);

    // Simular latencia mínima para UX
    setTimeout(() => {
      const resultado = procesarConsulta(pregunta.trim(), obras);
      setHistorial((prev) => [{ pregunta: pregunta.trim(), ...resultado }, ...prev].slice(0, 10));
      setPregunta("");
      setLoading(false);
    }, 200);
  }, [pregunta, obras]);

  const handleKeyDown = useCallback(
    (e) => { if (e.key === "Enter" && !e.shiftKey) handleConsultar(); },
    [handleConsultar]
  );

  const usarEjemplo = useCallback((ej) => {
    setPregunta(ej);
    inputRef.current?.focus();
  }, []);

  return (
    <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
      {/* Cabecera */}
      <div className="px-6 py-4 border-b border-gray-100 flex items-center gap-3"
           style={{ background: "linear-gradient(135deg, #691C32 0%, #550A1F 100%)" }}>
        <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center">
          <span className="text-base">🤖</span>
        </div>
        <div>
          <h3 className="text-white font-semibold text-sm">Asistente de consultas</h3>
          <p className="text-teal-100 text-xs">Pregunta en lenguaje natural sobre las obras</p>
        </div>
      </div>

      {/* Input */}
      <div className="p-4 border-b border-gray-100">
        <div className="flex gap-2">
          <input
            ref={inputRef}
            type="text"
            value={pregunta}
            onChange={(e) => setPregunta(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ej: ¿Cuántas obras se actualizaron?"
            disabled={loading}
            className="flex-1 px-4 py-2.5 text-sm rounded-lg border border-gray-300
              focus:outline-none focus:ring-2 focus:ring-teal-400 focus:border-teal-500
              disabled:opacity-50 disabled:bg-gray-50"
            aria-label="Campo para ingresar consulta"
          />
          <button
            onClick={handleConsultar}
            disabled={!pregunta.trim() || loading}
            className="px-4 py-2.5 bg-teal-600 hover:bg-teal-700 disabled:opacity-40
              text-white text-sm font-medium rounded-lg transition-colors
              focus:outline-none focus:ring-2 focus:ring-teal-400"
            aria-label="Realizar consulta"
          >
            {loading ? (
              <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin inline-block" />
            ) : (
              "Consultar"
            )}
          </button>
        </div>

        {/* Ejemplos rápidos */}
        <div className="flex flex-wrap gap-1.5 mt-3">
          {EJEMPLOS_CONSULTA.slice(0, 4).map((ej) => (
            <button
              key={ej}
              onClick={() => usarEjemplo(ej)}
              className="text-xs px-2.5 py-1 rounded-full border border-gray-200
                text-gray-500 hover:border-teal-400 hover:text-teal-600 hover:bg-teal-50
                transition-colors"
            >
              {ej}
            </button>
          ))}
        </div>
      </div>

      {/* Historial de respuestas */}
      {historial.length > 0 ? (
        <div className="divide-y divide-gray-50 max-h-64 overflow-y-auto">
          {historial.map((item, i) => (
            <div key={i} className="px-4 py-3 hover:bg-gray-50 transition-colors">
              <p className="text-xs text-gray-400 mb-1">
                <span className="text-gray-600 font-medium">Pregunta:</span> {item.pregunta}
              </p>
              <p className={`text-sm font-medium ${item.confianza > 0 ? "text-gray-800" : "text-gray-500"}`}>
                {item.confianza > 0 ? "💬 " : "❓ "}
                {item.respuesta}
              </p>

              {/* Sugerencias cuando no hay match */}
              {item.sugerencias?.length > 0 && (
                <div className="mt-2 flex flex-wrap gap-1">
                  {item.sugerencias.map((s) => (
                    <button
                      key={s}
                      onClick={() => usarEjemplo(s)}
                      className="text-xs px-2 py-0.5 rounded-full bg-gray-100 text-gray-600
                        hover:bg-teal-100 hover:text-teal-700 transition-colors"
                    >
                      {s}
                    </button>
                  ))}
                </div>
              )}

              {/* Confianza y SQL */}
              {item.confianza > 0 && (
                <div className="mt-1.5 flex items-center gap-3">
                  <span className={`text-xs px-2 py-0.5 rounded-full font-medium
                    ${item.confianza >= 0.9 ? "bg-green-100 text-green-700" : "bg-yellow-100 text-yellow-700"}`}>
                    {(item.confianza * 100).toFixed(0)}% confianza
                  </span>
                  {item.sql && (
                    <span className="text-xs text-gray-400 font-mono truncate max-w-[200px]" title={item.sql}>
                      {item.sql.slice(0, 50)}…
                    </span>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      ) : (
        <div className="px-4 py-8 text-center text-gray-400">
          <p className="text-sm">Realiza tu primera consulta arriba</p>
          <p className="text-xs mt-1">Los datos se toman en tiempo real de las obras cargadas</p>
        </div>
      )}
    </div>
  );
}

export default memo(OrchestradorPanel);
